/*******
 * Gets the days between inception and expiration date
 * By Adriana Centellas
*******/ 

// Data type Date
const dateA = new Date(this.CQP_INCEPTION_DATE);
const dateB = new Date(this.CQP_EXPIRATION_DATE);

// Calculate difference un miliseconds
const diffTime = dateB - dateA;

// To days
const diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24));

return diffDays;

/*******
 * Gets the months between inception and expiration date
 * By Adriana Centellas
*******/ 

const dateA = new Date(this.CQP_INCEPTION_DATE);
const dateB = new Date(this.CQP_EXPIRATION_DATE);

let months =
  (dateB.getFullYear() - dateA.getFullYear()) * 12 +
  (dateB.getMonth() - dateA.getMonth());

//In case expiration date is before inception date
if (dateB.getDate() < dateA.getDate()) {
  months--;
}

return months;

/*******
 * Gets the expiration adding the months selected on dropdown
 * By Adriana Centellas
***/

function addMonthsSafe(dateStr, monthsToAdd) {
  // Parse input
  const [yStr, mStr, dStr] = dateStr.split("-");
  let year = parseInt(yStr, 10);
  let month = parseInt(mStr, 10); // 1–12
  const day = parseInt(dStr, 10);
  const months = parseInt(monthsToAdd, 10);

  // Add the months directly
  month += months;

  // Adjust for overflow (more than 12 months)
  while (month > 12) {
    month -= 12;
    year++;
  }

  // Adjust for underflow (negative months)
  while (month < 1) {
    month += 12;
    year--;
  }

  // Determine how many days exist in the new target month
  const daysInTargetMonth = new Date(year, month, 0).getDate();

  // Clamp the day if it doesn't exist in the target month
  const newDay = Math.min(day, daysInTargetMonth);

  // Format to yyyy-mm-dd
  const formatted = `${year}-${String(month).padStart(2, "0")}-${String(newDay).padStart(2, "0")}`;

  return formatted;
}

return addMonthsSafe(this.CQP_INCEPTION_DATE, this.CQP_ADD_INCEPTION_DATE);

/*****
